import Navbar from "@/components/Navbar";
import { portfolioData } from "@/data/portfolio";
import Link from "next/link";
import { ArrowLeft } from "lucide-react";

export default function ProjectsPage() {
  return (
    <main className="relative min-h-screen bg-[#FCFAF5] overflow-hidden">
      {/* BACKGROUND */}
      <div className="pointer-events-none absolute inset-0 h-[400px] w-full">
        <div
          className="absolute inset-0"
          style={{
            backgroundImage: `
              linear-gradient(to right, rgba(0,0,0,0.06) 1px, transparent 1px),
              linear-gradient(to bottom, rgba(0,0,0,0.06) 1px, transparent 1px)
            `,
            backgroundSize: "32px 32px",
            WebkitMaskImage:
              "linear-gradient(to bottom, rgba(0,0,0,1), rgba(0,0,0,0))",
            maskImage:
              "linear-gradient(to bottom, rgba(0,0,0,1), rgba(0,0,0,0))",
          }}
        />
      </div>

      <div className="relative max-w-4xl mx-auto border-x border-neutral-200/60 min-h-screen flex flex-col">
        <Navbar />

        <div className="px-8 py-10 flex-grow">
          <Link
            href="/"
            className="inline-flex items-center gap-2 text-[13px] text-neutral-500 hover:text-neutral-800 mb-8 transition-colors group"
          >
            <ArrowLeft size={14} className="group-hover:-translate-x-0.5 transition-transform" />
            Home
          </Link>

          <h1 className="text-2xl font-medium text-neutral-900 mb-2">All Projects</h1>
          <p className="text-[14px] text-neutral-500 mb-10">
            A comprehensive list of things I've built, experimented with, or contributed to.
          </p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pb-20">
            {portfolioData.projects.map((project, index) => (
              <Link href={`/projects/${project.slug}`} key={index} className="block group">
                <div className="bg-white border border-neutral-200 p-5 rounded shadow-[0_1px_2px_rgba(0,0,0,0.03)] group-hover:border-blue-300 group-hover:shadow-sm transition-all h-full flex flex-col">
                  <h3 className="font-medium text-[15px] text-neutral-800 mb-1.5 group-hover:text-blue-600 transition-colors">
                    {project.title}
                  </h3>
                  <p className="text-[13px] text-neutral-500 leading-relaxed mb-6 flex-grow">
                    {project.description}
                  </p>
                  <div className="flex flex-wrap gap-2 mt-auto">
                    {project.tags.map((tag, i) => (
                      <span key={i} className="px-2 py-1 bg-[#FDFBF7] border border-neutral-200/60 text-neutral-600 text-[10px] rounded-md font-medium">
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>
    </main>
  );
}

"use client";

import { portfolioData } from "@/data/portfolio";
import { BadgeCheck, Instagram, Github, Download } from "lucide-react";

const COLORS = [
  { border: "border-blue-200", bg: "bg-blue-50", text: "text-blue-700" },
  { border: "border-green-200", bg: "bg-green-50", text: "text-green-700" },
  { border: "border-purple-200", bg: "bg-purple-50", text: "text-purple-700" },
  { border: "border-pink-200", bg: "bg-pink-50", text: "text-pink-700" },
];

export default function Hero() {
  return (
    <section className="w-full px-8 pb-12 pt-4 flex gap-6 items-start">

      {/* Avatar */}
      <img
        src={portfolioData.profile.avatar}
        alt="Profile"
        className="w-[120px] h-[120px] rounded-lg object-cover border border-neutral-200/60 shadow-sm bg-white"
      />

      <div className="flex-1">

        {/* Header */}
        <div className="flex items-center gap-3 mb-1 flex-wrap">
          <h1 className="text-[22px] font-medium text-neutral-900">
            {portfolioData.profile.name}
          </h1>

          <BadgeCheck
            size={18}
            className="text-blue-500"
            fill="currentColor"
            stroke="white"
          />

          {/* Social */}
          <a
            href="https://instagram.com"
            target="_blank"
            rel="noopener noreferrer"
            className="text-neutral-500 hover:text-neutral-800 transition-colors"
          >
            <Instagram size={16} />
          </a>
          <a
            href="https://github.com"
            target="_blank"
            rel="noopener noreferrer"
            className="text-neutral-500 hover:text-neutral-800 transition-colors"
          >
            <Github size={16} />
          </a>

          {/* Resume */}
          <a
            href="/resume.pdf"
            download
            className="ml-2 inline-flex items-center gap-2 px-3 py-1.5 text-[12px]
                       border border-neutral-300/60 rounded-md
                       bg-white/40 backdrop-blur-sm
                       hover:border-blue-400 hover:text-blue-600
                       transition-all duration-200"
          >
            <Download size={14} />
            Resume / CV
          </a>
        </div>

        {/* Title */}
        <div className="flex items-center gap-2 mb-3">
          <p className="text-[13px] text-neutral-400 font-medium">
            {portfolioData.profile.title}
          </p>
          <span className="text-[11px] text-neutral-300">|</span>
          <p className="text-[12px] font-medium text-blue-600 bg-blue-50/80 border border-blue-100 px-2 py-0.5 rounded-md shadow-sm">
            {portfolioData.profile.position}
          </p>
        </div>

        {/* Bio */}
        <p className="text-[14px] leading-relaxed text-neutral-600 max-w-2xl">
          {portfolioData.profile.bio.intro}{" "}

          {portfolioData.profile.bio.tech.map((tech, i) => {
            const color = COLORS[i % COLORS.length];
            const rotation = i % 2 === 0 ? -2 : 2;

            return (
              <span
                key={tech}
                style={{ rotate: `${rotation}deg` }}
                className={
                  "inline-block mx-1 px-2 py-[2px] text-[12px] font-medium " +
                  color.border +
                  " " +
                  color.bg +
                  " " +
                  color.text +
                  " rounded-md shadow-sm " +
                  "transition-all duration-200 " +
                  "hover:scale-105 hover:-translate-y-[1px]"
                }
              >
                {tech}
              </span>
            );
          })}

          .
        </p>
      </div>
    </section>
  );
}
